	border-radius: 10px;
&#125;

.article-tags .chip:hover &#123;
	background: linear-gradient(to bottom right,#FF5E3A 0%,#9ce525 100%) !important;
	box-shadow: 2px 5px 10px #aaa !important;
&#125;

.prev-next &#123;
	margin-left: -0.75rem;
&#125;

.prev-next .article-badge &#123;
	min-width: 3rem;
